package ru.memearena.analytics.infrastructure;
import org.springframework.data.jpa.repository.*; import org.springframework.data.repository.query.Param; import ru.memearena.analytics.domain.ProductEvent; import java.time.Instant; import java.util.UUID;
public interface ProductEventRepository extends JpaRepository<ProductEvent, UUID> { @Query("select count(distinct e.userId) from ProductEvent e where e.receivedAt between :from and :to and e.userId is not null") long activeUsers(@Param("from") Instant from,@Param("to") Instant to); @Query("select count(e) from ProductEvent e where e.eventType = ru.memearena.analytics.domain.ProductEventType.APP_OPENED and e.receivedAt between :from and :to") long appOpens(@Param("from") Instant from,@Param("to") Instant to); @Query("select count(distinct e.userId) from ProductEvent e where e.eventType = ru.memearena.analytics.domain.ProductEventType.BATTLE_OPENED and e.receivedAt between :from and :to and e.userId is not null") long usersWhoOpenedBattle(@Param("from") Instant from,@Param("to") Instant to); @Query("select count(distinct e.userId) from ProductEvent e where e.eventType = ru.memearena.analytics.domain.ProductEventType.VOTE_COMPLETED and e.receivedAt between :from and :to and e.userId is not null") long usersWhoCompletedVote(@Param("from") Instant from,@Param("to") Instant to); }
